import React, { useState, useMemo, useEffect } from "react";

const DATA = {"nodes": [{"id": "n_root", "parent_id": null, "evidence_quality": "well-evidenced", "label": "What does the evidence say about social media's effects on adolescent mental health \u2014 and on which question, exactly?", "children": ["n_assoc", "n_trend", "n_mech", "n_policy"], "role": "topic", "question": {"research": "What does the evidence say about social media's effects on adolescent mental health \u2014 and on which question, exactly?", "simple": "Is social media harming teenagers?"}, "depends_on": {"research": "'Harmful' is not one measurable quantity. The literature separately measures the individual-level association, whether it is causal, whether it explains the population trend since ~2010, the mechanism, and what restriction policies change \u2014 with sharply different degrees of consensus. Public debate routinely lets confidence on one of these stand in for all of them; this tree exists to keep them apart.", "simple": "There's no single 'is it harmful' score. Whether heavy users feel worse, whether social media is the cause, whether it explains why teen mental health got worse, and whether bans help are four different questions with different-quality evidence. Pick one."}, "coverage_note": "Authored dimensions: individual association & causation, the population trend, mechanisms, restriction policies. DELIBERATELY NOT COVERED (invisible to this tool): content-specific harms with their own literatures (cyberbullying prevalence, grooming/exploitation, CSAM, pro-self-harm content exposure); 'problematic use'/addiction as a clinical construct; effects on adults; polarization and civic effects; physical-health outcomes; platform-by-platform design comparisons; privacy/data-rights harms; and whether age bans are JUSTIFIED all things considered \u2014 a values question this tool records no verdict on. Absence is a scope choice, not evidence of no effect. Note also: 'screen time' is not 'social media use'; findings based on general screen measures are labelled as such and must not be read as social-media-specific.", "scored": false, "evidence_caveats": []}, {"id": "n_assoc", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "How is social media use related to individual adolescents' mental health \u2014 and is the relationship causal?", "children": ["n_assoc_magnitude", "n_assoc_causal", "n_assoc_hetero", "n_assoc_benefits"], "role": "dimension", "question": {"research": "How is social media use related to individual adolescents' mental health \u2014 and is the relationship causal?", "simple": "Do teens who use social media more actually feel worse \u2014 and is social media the reason?"}, "depends_on": {"research": "Depends on WHICH question (correlation magnitude vs. causal effect), HOW use is measured (self-report inflates associations relative to device logs), WHO (average adolescent vs. vulnerable subgroups and developmental windows), and WHICH direction of effect (harms and benefits can coexist in the same population).", "simple": "Depends on what you're asking (do heavy users feel worse, or does social media make them feel worse \u2014 not the same thing), how use is measured (people misremember their own use), and which teens you mean (averages can hide groups who are hit harder \u2014 or helped)."}, "coverage_note": "Captures individual-level association, causal evidence, heterogeneity, and benefits. Does not cover clinical 'problematic use' constructs, and platform-specific differences (e.g. image-based vs. text-based) are visible only where a finding happens to carry them.", "scored": false, "evidence_caveats": ["mostly correlational \u2014 causal interpretation is not licensed", "self-reported use dominates \u2014 device-log associations run weaker"]}, {"id": "n_assoc_magnitude", "parent_id": "n_assoc", "evidence_quality": "well-evidenced", "label": "Is heavier social media use meaningfully associated with worse adolescent depression and anxiety?", "children": [], "role": "leaf", "question": {"research": "Is heavier social media use meaningfully associated with worse adolescent depression and anxiety?", "simple": "Do teens who use social media more report feeling worse?"}, "claim_evaluated": {"research": "Heavier social media use is associated with worse depression/anxiety in adolescents at a magnitude that is practically meaningful, not trivially small.", "simple": "Teens who spend more time on social media report noticeably worse mental health \u2014 the link is big enough to matter."}, "depends_on": {"research": "The live dispute is magnitude, not existence: pooled correlations around r 0.2 (problematic-use measures higher) vs. specification-curve work bounding variance explained near zero. What counts as 'practically meaningful' is itself contested; findings must report the number, not the adjective.", "simple": "Almost everyone agrees there's SOME link. The fight is over whether it's big enough to matter \u2014 so look at the actual size, not the headline."}, "scored": true, "evidence_caveats": ["mostly correlational \u2014 causal interpretation is not licensed", "self-reported use dominates \u2014 device-log associations run weaker"]}, {"id": "n_assoc_causal", "parent_id": "n_assoc", "evidence_quality": "well-evidenced", "label": "Does social media use causally worsen adolescent mental health?", "children": [], "role": "leaf", "question": {"research": "Does social media use causally worsen adolescent mental health?", "simple": "Does social media actually cause worse mental health \u2014 not just go along with it?"}, "claim_evaluated": {"research": "Social media use causally worsens adolescent mental health.", "simple": "Social media makes teens' mental health worse (it's the cause, not just a coincidence)."}, "depends_on": {"research": "Depends on the causal contrast: platform introduction (quasi-experiments), short-run individual deactivation (RCTs, mostly adult samples), and lifelong non-adoption answer different questions. A causal effect in one contrast does not establish the others.", "simple": "Depends what you compare: what happened when social media first arrived, what happens when someone quits for a few weeks, and what a life without it would be like are three different questions."}, "scored": true, "evidence_caveats": ["strongest designs use 2000s college students and adult samples \u2014 transportability to today's adolescents not established"]}, {"id": "n_assoc_hetero", "parent_id": "n_assoc", "evidence_quality": "thin", "label": "Are harms concentrated in vulnerable subgroups and developmental windows rather than uniform?", "children": [], "role": "leaf", "question": {"research": "Are harms concentrated in vulnerable subgroups and developmental windows rather than uniform?", "simple": "Are some teens \u2014 like young girls \u2014 hit much harder than others?"}, "claim_evaluated": {"research": "Negative effects of social media are concentrated in specific subgroups and developmental windows (notably girls in early adolescence) rather than spread uniformly.", "simple": "Social media's harms hit certain groups \u2014 especially girls around ages 11\u201313 \u2014 much harder than teens in general."}, "depends_on": {"research": "If true, population-average effects understate risk for the sensitive groups and overstate it for everyone else \u2014 which changes what both the null-average findings and the alarm-raising findings mean.", "simple": "If some groups are hit hard while most aren't, then 'on average it's fine' and 'it's harming kids' can both be half-true."}, "scored": true, "evidence_caveats": ["no independent AGAINST located \u2014 one-sided", "mostly correlational \u2014 causal interpretation is not licensed"]}, {"id": "n_assoc_benefits", "parent_id": "n_assoc", "evidence_quality": "thin", "label": "Does social media provide real mental-health-relevant benefits to some adolescents?", "children": [], "role": "leaf", "question": {"research": "Does social media provide real mental-health-relevant benefits to some adolescents?", "simple": "Does social media genuinely help some teens?"}, "claim_evaluated": {"research": "Social media provides real mental-health-relevant benefits to some adolescents \u2014 community, connection, and support, especially for marginalized youth.", "simple": "For some teens \u2014 especially ones who feel isolated where they live \u2014 social media genuinely helps, giving them community and support."}, "depends_on": {"research": "Depends on WHICH adolescents (marginalized youth, e.g. LGBTQ+ teens in unsupportive environments, are the strongest case) and whether benefits are weighed within the same population that carries the harms \u2014 both can be true at once.", "simple": "Depends which teens you mean. The strongest case is kids who can't find their community offline. Helping some and harming others can both be true."}, "scored": true, "evidence_caveats": ["no independent AGAINST located \u2014 one-sided, single-source FOR", "largely qualitative and self-report evidence"]}, {"id": "n_trend", "parent_id": "n_root", "evidence_quality": "thin", "label": "Did adolescent mental health really deteriorate after ~2010, and is social media the driver?", "children": ["n_trend_real", "n_trend_attrib"], "role": "dimension", "question": {"research": "Did adolescent mental health really deteriorate after ~2010, and is social media the driver?", "simple": "Did teen mental health really get worse since about 2010 \u2014 and is social media why?"}, "depends_on": {"research": "Two separable claims: that the deterioration is real (vs. changed reporting, screening, and diagnostic practice) and that social media adoption is its principal cause. The second presupposes the first but does not follow from it \u2014 the timing coincidence plus an individual-level association is not, by itself, population-level attribution.", "simple": "First question: did things really get worse, or are teens just more willing to report problems? Second question: even if it's real, is social media the reason? Yes to the first doesn't mean yes to the second."}, "coverage_note": "Covers the reality and the attribution of the post-2010 trend in high-income countries. Competing explanations (economic insecurity, academic pressure, parenting shifts, opioid-era spillovers) are visible only as they appear inside attribution findings; they are not separately scored.", "scored": false, "evidence_caveats": ["Anglosphere/Nordic-centric evidence \u2014 external validity not established"]}, {"id": "n_trend_real", "parent_id": "n_trend", "evidence_quality": "thin", "label": "Has adolescent mental health genuinely deteriorated since ~2010?", "children": [], "role": "leaf", "question": {"research": "Has adolescent mental health genuinely deteriorated since ~2010?", "simple": "Did teen mental health really get worse \u2014 or are teens just reporting it more?"}, "claim_evaluated": {"research": "Adolescent mental health has genuinely deteriorated since ~2010; the rise is not an artifact of changed reporting, screening, or diagnostic practice.", "simple": "Teen mental health really did get worse after about 2010 \u2014 it's not just that teens talk about it more now."}, "depends_on": {"research": "Depends on the outcome series: self-report symptom scales are vulnerable to reporting change; hospitalizations and suicide statistics are harder to explain away but have their own recording issues. Measurement-invariance tests are the direct evidence on the artifact question.", "simple": "Surveys can shift because attitudes shift. Harder numbers \u2014 hospital visits, suicides \u2014 are more convincing, but even those have counting quirks."}, "scored": true, "evidence_caveats": ["single-source-heavy: nordic-trend supplies 2/3 findings here", "no full AGAINST located \u2014 artifact hypothesis carried via COMPLICATES only", "Anglosphere/Nordic-centric evidence \u2014 external validity not established"]}, {"id": "n_trend_attrib", "parent_id": "n_trend", "evidence_quality": "thin", "label": "Is social media adoption the principal driver of the post-2010 deterioration?", "children": [], "role": "leaf", "question": {"research": "Is social media adoption the principal driver of the post-2010 deterioration?", "simple": "Is social media the main reason teen mental health got worse?"}, "claim_evaluated": {"research": "Social media adoption is the principal driver of the post-2010 deterioration in adolescent mental health.", "simple": "Social media is the main cause of the decline in teen mental health since about 2010."}, "depends_on": {"research": "This is the map's most conflation-prone claim: it inherits unearned confidence from the association and causation leaves. Scaling an individual-level effect into the principal population driver requires additional assumptions (dose, coverage, absence of comparable rival shocks) that must be argued, not assumed.", "simple": "This is where people cheat: 'heavy users feel worse' quietly becomes 'social media caused the whole decline.' The second claim needs much more proof than the first."}, "scored": true, "evidence_caveats": ["single-source-heavy: twenge supplies 2/4 findings here", "correlational timing evidence \u2014 causal interpretation is not licensed"]}, {"id": "n_mech", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "Through what pathway would social media harm adolescents \u2014 and which pathways are actually evidenced?", "children": ["n_mech_sleep"], "role": "dimension", "question": {"research": "Through what pathway would social media harm adolescents \u2014 and which pathways are actually evidenced?", "simple": "HOW would social media hurt teens \u2014 and which explanation has real evidence?"}, "depends_on": {"research": "Proposed pathways differ in testability. Sleep displacement is separately measurable and is scored here. Social comparison and algorithmic amplification are evidenced mainly as mechanism findings inside other studies (e.g. the Facebook-rollout comparison evidence) and via expert synthesis \u2014 they surface in this map as findings and crosslinks on the causal leaves, not as scored leaves of their own.", "simple": "Some explanations can be measured on their own \u2014 like whether phones cost teens sleep \u2014 so that one gets scored. Others, like 'comparing yourself to others online', show up inside other studies rather than as their own yes/no question."}, "coverage_note": "Only sleep displacement is scored. Social comparison, algorithmic amplification, and displacement of in-person time are DELIBERATELY NOT scored as leaves \u2014 the literature evidences them as embedded mechanism findings rather than as independently testable claims with good-faith evidence on both sides; forcing them into scored leaves would manufacture false balance. They remain visible via findings and crosslinks on n_assoc_causal. This is a Phase 1 scope decision, revisitable if the mechanism literature matures.", "scored": false, "evidence_caveats": ["screens \u2260 social media \u2014 much of this literature measures devices generally"]}, {"id": "n_mech_sleep", "parent_id": "n_mech", "evidence_quality": "well-evidenced", "label": "Does social media / device use displace or degrade adolescent sleep?", "children": [], "role": "leaf", "question": {"research": "Does social media / device use displace or degrade adolescent sleep?", "simple": "Do phones and social media cost teens sleep?"}, "claim_evaluated": {"research": "Social media and portable-device use displaces or degrades adolescent sleep (quantity and quality).", "simple": "Phones and social media meaningfully cut into how much and how well teens sleep."}, "depends_on": {"research": "Most of this literature measures screens/devices generally, not social media specifically \u2014 every finding must state which. Between-person associations also run larger than within-person (same teen, day-to-day) estimates; the design must be stated.", "simple": "Watch two things: many studies measure ALL screen use, not just social media; and comparing different teens gives bigger numbers than following the same teen night by night."}, "scored": true, "evidence_caveats": ["screens \u2260 social media \u2014 both meta-analyses measure devices/screens generally", "single cluster per direction \u2014 two strong meta-analyses, one each way"]}, {"id": "n_policy", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "What do restriction policies \u2014 school phone bans, individual deactivation, age-based platform bans \u2014 measurably change?", "children": ["n_policy_school", "n_policy_deact", "n_policy_ban"], "role": "dimension", "question": {"research": "What do restriction policies \u2014 school phone bans, individual deactivation, age-based platform bans \u2014 measurably change?", "simple": "Do phone bans and social media bans actually work?"}, "depends_on": {"research": "Depends on the intervention's dose and scope (school-hours phone removal vs. weeks of personal deactivation vs. society-wide age limits), on the outcome measured (use, wellbeing, grades), and on enforcement. Evidence that harm exists does not establish that a given restriction reduces it \u2014 and a restriction failing to reduce USE says nothing yet about what reduced use would do.", "simple": "'Does it work' depends on which ban (phones out of class, quitting for a month, a national age limit), what you count as working (less use? happier kids? better grades?), and whether kids can just work around it."}, "coverage_note": "Covers what restriction policies measurably change. Whether bans are JUSTIFIED (autonomy, proportionality, enforcement costs, expression rights) is a values question outside this map. Age-verification technology and its privacy costs are not scored.", "scored": false, "evidence_caveats": ["fast-moving policy literature \u2014 several key sources are 2024\u20132026 working papers"]}, {"id": "n_policy_school", "parent_id": "n_policy", "evidence_quality": "well-evidenced", "label": "Do school smartphone bans improve student mental health and academic outcomes?", "children": [], "role": "leaf", "question": {"research": "Do school smartphone bans improve student mental health and academic outcomes?", "simple": "Does banning phones in school help kids do and feel better?"}, "claim_evaluated": {"research": "School smartphone bans improve student mental health and academic outcomes.", "simple": "Banning phones in school improves kids' mental health and grades."}, "depends_on": {"research": "Depends on policy dose (bell-to-bell vs. classroom-only), on design (causal ban-timing studies vs. cross-sectional policy comparisons \u2014 the headline null and the headline positive currently come from different designs and countries), and on which subgroup (reported gains concentrate among girls and lower-achieving students).", "simple": "Depends how strict the ban is, how the study was run (the 'it works' and 'no difference' headlines come from different kinds of studies), and which kids you look at."}, "scored": true, "evidence_caveats": ["working-paper-heavy FOR side \u2014 peer review pending", "design mismatch: causal ban-timing studies vs cross-sectional policy comparison"]}, {"id": "n_policy_deact", "parent_id": "n_policy", "evidence_quality": "well-evidenced", "label": "Does individually reducing or deactivating social media improve wellbeing?", "children": [], "role": "leaf", "question": {"research": "Does individually reducing or deactivating social media improve wellbeing?", "simple": "Does quitting or cutting back on social media make people feel better?"}, "claim_evaluated": {"research": "Individually reducing or deactivating social media use improves subjective wellbeing.", "simple": "People who quit or cut back on social media end up feeling better."}, "depends_on": {"research": "Depends on duration (days vs. weeks), sample (landmark RCTs are adult samples \u2014 adolescent transportability is an assumption), and aggregation (competing meta-analyses of the same RCT pool reach opposite headlines and are themselves disputed). Short-run individual deactivation also cannot estimate population-wide or never-adoption effects.", "simple": "Depends how long people quit, who was studied (mostly adults, not teens), and which summary you trust \u2014 rival round-ups of the same experiments disagree. And one person quitting for a month is not the same as nobody having it."}, "scored": true, "evidence_caveats": ["adult samples throughout \u2014 adolescent transportability assumed, not shown"]}, {"id": "n_policy_ban", "parent_id": "n_policy", "evidence_quality": "thin", "label": "Do age-based platform bans actually reduce under-age social media use?", "children": [], "role": "leaf", "question": {"research": "Do age-based platform bans actually reduce under-age social media use?", "simple": "Do national age limits actually keep kids off social media?"}, "claim_evaluated": {"research": "Age-based platform bans (the Australian under-16 model) effectively reduce under-age social media use.", "simple": "National bans like Australia's actually keep under-16s off social media."}, "depends_on": {"research": "Deliberately scoped to USE, not mental health: no mental-health outcome data from any national ban exists yet. Early evidence measures one quarter of a contested rollout \u2014 an early null on use-reduction is not evidence about the mental-health effects of a well-enforced ban, and must not be laundered into one (nor the reverse).", "simple": "This asks only whether bans keep kids off the apps \u2014 nobody yet has data on whether banned kids feel better. Early results from Australia measure just the first few months, when enforcement was leaky."}, "scored": true, "evidence_caveats": ["single-source-heavy: aus-ban-eval supplies 2/2 findings here", "no qualifying FOR evidence \u2014 one-sided, single-source", "three-month early evidence during contested rollout \u2014 measures use, not mental health"]}], "findings": [{"finding_id": "F-root-1", "node_id": "n_root", "direction": "COMPLICATES", "claim_paragraph": {"research": "The literature never measures 'is social media harming teenagers?' directly. It separately measures the individual-level association, whether that association is causal, whether social media explains the population trend since ~2010, the mechanism, and what restriction policies change \u2014 each with its own data, methods, and degree of consensus. The 2024 National Academies consensus report is explicit that these questions have different answers: it affirms that specific design features can harm some young people while declining to endorse a population-level causal conclusion.", "simple": "No study measures 'is social media bad for teens' all at once. Researchers ask separate questions \u2014 do heavy users feel worse, does social media cause it, did it drive the rise in teen distress, and do bans help \u2014 and the answers differ. Pick a question first; being sure about one doesn't make you right about the others."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "National Academies of Sciences, Engineering, and Medicine 2024, Social Media and Adolescent Health (consensus report).", "triggers_split_to": ["n_assoc", "n_trend", "n_mech", "n_policy"], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2024", "caveat": {"research": "Consensus synthesis across studies of varying design and quality.", "simple": "A committee round-up of many studies of mixed quality."}}, {"finding_id": "F-root-2", "node_id": "n_root", "direction": "COMPLICATES", "claim_paragraph": {"research": "Evidence quality is sharply uneven across the sub-questions. Correlational associations are measured in hundreds of studies; causal evidence is a handful of quasi-experiments and RCTs, mostly on adults; population-trend attribution rests largely on timing correlations; and national-ban evidence barely exists. Most research to date is correlational and has generated a mix of small positive, negative, and null associations \u2014 confidence earned on the best-measured sub-question does not transfer to the others.", "simple": "We know a lot about some parts and almost nothing about others. There are hundreds of studies on whether heavy users feel worse, only a few good experiments on whether social media is the cause, and almost no evidence yet on national bans. Don't let the well-studied part vouch for the rest."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Odgers & Jensen 2020, Annual Research Review, Journal of Child Psychology and Psychiatry 61:336-348.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "odgers-review", "caveat": {"research": "Narrative annual review, not a formal systematic search; pre-2020 literature.", "simple": "An expert overview rather than a full formal count of every study; from 2020."}}, {"finding_id": "F-assoc-1", "node_id": "n_assoc", "direction": "COMPLICATES", "claim_paragraph": {"research": "Two distinctions govern this whole dimension. First, association is not causation: distressed adolescents may use more social media rather than the reverse, and the leading review concludes the correlational designs 'do not offer a way of distinguishing cause from effect'. Second, measurement matters: most studies rely on self-reported use, and associations measured from device logs run substantially weaker than self-report-based ones.", "simple": "Two traps here. Unhappy teens might use social media more because they're unhappy \u2014 not the other way round. And most studies ask teens to guess their own screen time; when researchers check the phone's actual logs, the link with feeling bad gets weaker."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Odgers & Jensen 2020, J. Child Psychology & Psychiatry 61:336-348; Orben & Przybylski 2019, Nature Human Behaviour.", "triggers_split_to": ["n_assoc_magnitude", "n_assoc_causal"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "odgers-review", "caveat": {"research": "A methodological framing, not a direct measurement.", "simple": "A point about how studies work, not a new measurement."}}, {"finding_id": "F-mag-1", "node_id": "n_assoc_magnitude", "direction": "SUPPORTS", "claim_paragraph": {"research": "Meta-analysis of problematic social media use in adolescents and young adults finds moderate, statistically significant pooled correlations with depression (r = 0.27), anxiety (r = 0.35), and stress (r = 0.31). On the 'problematic use' construct \u2014 use with addiction-like features, not mere time spent \u2014 the association is not trivially small.", "simple": "When researchers pool studies of teens whose social media use looks compulsive \u2014 not just heavy \u2014 those teens report clearly worse depression, anxiety, and stress. On that measure, the link is real and not tiny."}, "effect_size": {"research": "pooled r = 0.27 (depression), 0.35 (anxiety)", "simple": "a clear, moderate link for compulsive-style use"}, "source_type": "meta-analysis", "source_citation": "Shannon et al. 2022, Problematic Social Media Use in Adolescents and Young Adults: Systematic Review and Meta-analysis, JMIR Mental Health 9(4):e33450.", "triggers_split_to": [], "tension_with": ["F-mag-4"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "jmir-problematic-meta", "caveat": {"research": "'Problematic use' is a clinical-adjacent construct; results do not transfer to time-spent measures. Cross-sectional, self-report inputs \u2014 no causal direction.", "simple": "This measures compulsive-style use, not hours. It also can't say which came first, the use or the distress."}}, {"finding_id": "F-mag-2", "node_id": "n_assoc_magnitude", "direction": "SUPPORTS", "claim_paragraph": {"research": "A meta-analysis of 2020-2024 evidence on social-networking-site use and mental disorders in adolescents and young adults finds a significant positive pooled association of small-to-moderate magnitude (r \u2248 0.22) between exposure to SNS-related risk factors and mental-health problems \u2014 the recent literature, taken together, does not support a zero effect.", "simple": "Pooling the newest studies (2020-2024), teens and young adults more exposed to social media risk factors report somewhat worse mental health. The newest evidence, added up, does not say 'no link at all'."}, "effect_size": {"research": "pooled r \u2248 0.22", "simple": "a small-to-moderate link"}, "source_type": "meta-analysis", "source_citation": "Associations Between Social Media Use and Mental Disorders in Adolescents and Young Adults: A Systematic Review and Meta-Analysis of Recent Evidence, Behavioral Sciences 15(11):1450 (2025).", "triggers_split_to": [], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "recent-sns-meta", "caveat": {"research": "Heterogeneous designs and exposure definitions pooled; overwhelmingly correlational, self-report inputs.", "simple": "Mixes many kinds of studies, almost all of which just compare users rather than testing causes."}}, {"finding_id": "F-mag-3", "node_id": "n_assoc_magnitude", "direction": "SUPPORTS", "claim_paragraph": {"research": "A dose-response meta-analysis of time spent on social media and adolescent depression finds depression risk rising with hours of daily use \u2014 the association is not flat across the usage range, which is what a purely spurious link would more easily produce.", "simple": "Adding up studies that track hours: the more time teens spend on social media each day, the higher their odds of depression, step by step. The risk climbs with the dose, which makes a pure coincidence less likely \u2014 though it still doesn't prove cause."}, "effect_size": {"research": "monotone dose-response of depression risk in daily hours", "simple": "risk climbs with each extra daily hour"}, "source_type": "meta-analysis", "source_citation": "Time Spent on Social Media and Risk of Depression in Adolescents: A Dose-Response Meta-Analysis (2022; PMC9103874).", "triggers_split_to": [], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "dose-response-meta", "caveat": {"research": "Observational inputs with self-reported time; dose-response is consistent with but does not establish causation (reverse causation can also be dose-shaped).", "simple": "Based on teens' own time estimates; more-distressed teens could also be choosing to use more."}}, {"finding_id": "F-mag-4", "node_id": "n_assoc_magnitude", "direction": "CHALLENGES", "claim_paragraph": {"research": "Specification-curve analysis across three large adolescent datasets shows digital-technology use explains at most ~0.4% of the variation in well-being, and that defensible analytic choices can produce positive, negative, or null associations from the same data. Companion time-use-diary analyses find comparably tiny associations. On population-representative time-spent measures, the association is real but trivially small.", "simple": "When researchers ran every reasonable version of the analysis on three huge datasets, screen and social media time explained well under 1% of the difference in how teens feel \u2014 and choosing the analysis differently could make the link look good, bad, or absent. On ordinary hours-spent measures, the link is tiny."}, "effect_size": {"research": "\u22640.4% of well-being variance explained", "simple": "tiny \u2014 under 1% of the differences between teens"}, "source_type": "single-study", "source_citation": "Orben & Przybylski 2019, The association between adolescent well-being and digital technology use, Nature Human Behaviour 3:173-182; Orben & Przybylski 2019, Screens, Teens, and Psychological Well-Being, Psychological Science 30(5).", "triggers_split_to": [], "tension_with": ["F-cau-1", "F-mag-1", "F-het-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "orben-przybylski", "caveat": {"research": "Measures broad digital-technology/screen use more than social media specifically; cross-sectional variance-explained is not an estimate of any causal effect.", "simple": "Counts all screen time, not just social media \u2014 and a tiny average link doesn't rule out real effects for some teens or from causes."}}, {"finding_id": "F-mag-5", "node_id": "n_assoc_magnitude", "direction": "CHALLENGES", "claim_paragraph": {"research": "The leading annual research review concludes that the most rigorous large-scale preregistered studies report small associations between daily digital-technology use and adolescent well-being that 'are unlikely to be of clinical or practical significance', and that the wider literature is a mix of conflicting small positive, negative, and null associations.", "simple": "A major expert review of the best big studies concludes the link between daily use and how teens feel is small \u2014 probably too small to matter in practice \u2014 and that studies disagree, finding small good, bad, and no effects."}, "effect_size": {"research": "small; 'unlikely to be of clinical or practical significance'", "simple": "small \u2014 likely too small to matter in practice"}, "source_type": "systematic-review", "source_citation": "Odgers & Jensen 2020, Annual Research Review, J. Child Psychology & Psychiatry 61:336-348.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "odgers-review", "caveat": {"research": "Narrative review; covers literature to 2019, before the strongest quasi-experimental work and the newest platforms.", "simple": "An expert overview from 2020 \u2014 written before some newer, stronger studies."}}, {"finding_id": "F-cau-1", "node_id": "n_assoc_causal", "direction": "SUPPORTS", "claim_paragraph": {"research": "Exploiting the staggered rollout of Facebook across US colleges (2004-2006) as a natural experiment, Facebook's arrival worsened student mental health and increased self-reported academic impairment due to poor mental health; mechanism evidence points to unfavorable social comparison. This is the strongest causal identification in the literature, and it finds harm.", "simple": "When Facebook arrived at some US colleges before others, researchers could compare. Students' mental health got worse when Facebook arrived \u2014 the best natural experiment we have, and it points to harm, likely from comparing yourself to others."}, "effect_size": {"research": "negative effect on a standardized mental-health index; qualitative here", "simple": "a real worsening, modest in size"}, "source_type": "single-study", "source_citation": "Braghieri, Levy & Makarin 2022, Social Media and Mental Health, American Economic Review 112(11):3660-3693.", "triggers_split_to": [], "tension_with": ["F-mag-4", "F-att-1", "F-ben-1"], "source_strength": "moderate", "evidence_type": "quasi-experimental", "source_cluster": "econ-quasiexp", "caveat": {"research": "College students in 2004-2006, one platform, US only \u2014 transportability to 2020s adolescents and today's algorithmic platforms not established.", "simple": "It studied US college students twenty years ago on early Facebook \u2014 today's teens and apps may differ."}}, {"finding_id": "F-cau-2", "node_id": "n_assoc_causal", "direction": "SUPPORTS", "claim_paragraph": {"research": "In a large randomized experiment (n \u2248 2,743), paying users to deactivate Facebook for the four weeks before the 2018 US midterms increased subjective well-being and offline activity. If removal improves well-being, continued use plausibly imposes a real ongoing cost \u2014 experimental evidence consistent with causal harm.", "simple": "In a big experiment, people paid to switch off Facebook for a month felt better and spent more time offline with others. If turning it off helps, having it on was probably costing something."}, "effect_size": {"research": "positive SWB gain from 4-week deactivation", "simple": "a real but modest mood boost from a month off"}, "source_type": "single-study", "source_citation": "Allcott, Braghieri, Eichmeyer & Gentzkow 2020, The Welfare Effects of Social Media, American Economic Review 110(3).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "experimental", "source_cluster": "allcott-gentzkow", "caveat": {"research": "Adult sample \u2014 transportability to adolescents is an assumption; short-run withdrawal is not the effect of never adopting.", "simple": "Done on adults, not teens \u2014 and a month's break isn't the same as growing up without it."}}, {"finding_id": "F-cau-3", "node_id": "n_assoc_causal", "direction": "CHALLENGES", "claim_paragraph": {"research": "The National Academies consensus committee, after reviewing the full literature, concluded that the available evidence 'did not support the conclusion that social media causes changes in adolescent health at the population level' \u2014 while acknowledging that specific design features can harm some young people. The strongest institutional synthesis declines to certify the causal claim.", "simple": "The biggest expert committee to review all the evidence would NOT sign off on 'social media causes worse teen health overall'. They do say some features can harm some kids \u2014 but the sweeping causal claim isn't supported yet, in their view."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "National Academies of Sciences, Engineering, and Medicine 2024, Social Media and Adolescent Health.", "triggers_split_to": [], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2024", "caveat": {"research": "Absence of certified population-level causation is not evidence of absence; the committee's bar is deliberately high.", "simple": "'Not proven' is not the same as 'proven harmless' \u2014 the committee sets a high bar."}}, {"finding_id": "F-cau-4", "node_id": "n_assoc_causal", "direction": "CHALLENGES", "claim_paragraph": {"research": "A preregistered meta-analysis of 27 social-media reduction and exposure experiments found a pooled effect around d \u2248 0.09 whose confidence interval includes zero \u2014 no reliable average causal effect of experimentally changing social media use on mental health.", "simple": "One researcher added up 27 experiments where people cut back on social media. On average, the benefit was so small it might be zero."}, "effect_size": {"research": "pooled d \u2248 0.09, 95% CI includes zero", "simple": "possibly zero on average"}, "source_type": "meta-analysis", "source_citation": "Ferguson 2024, Do social media experiments prove a link with mental health: a methodological and meta-analytic review, Psychology of Popular Media.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "review", "source_cluster": "reduction-rct-pool", "caveat": {"research": "DISPUTED: published critiques (Rausch & Haidt 2025, SSRN 5224958) allege errors in effect sizes, sample sizes, and inclusion criteria; a 2025 reanalysis of the same pool finds benefits emerge for longer interventions. Carry this finding together with its dispute.", "simple": "Heavily contested: critics say it contains real errors, and a re-analysis of the same experiments found longer breaks DO help. Read it alongside its critics."}}, {"finding_id": "F-cau-5", "node_id": "n_assoc_causal", "direction": "COMPLICATES", "claim_paragraph": {"research": "The causal question is really three: what platform INTRODUCTION did (quasi-experiments on rollout), what short-run individual DEACTIVATION does (RCTs, mostly adults), and what never-adopting or population-wide absence would do (essentially unmeasured). Positive evidence in one contrast does not establish the others \u2014 deactivation experiments, for instance, leave the participant in a world where everyone else is still online.", "simple": "'Does it cause harm' hides three different questions: what happened when it arrived, what happens when one person quits for a few weeks, and what a world without it would be like. Evidence on one doesn't settle the others \u2014 someone who quits still lives among friends who haven't."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "National Academies 2024 (evidence-limitations discussion); Allcott et al. 2020 AER (interpretation discussion).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "NAS-2024", "caveat": {"research": "A framing of the evidence's limits, not a measurement.", "simple": "A point about what the studies can and can't tell us."}}, {"finding_id": "F-het-1", "node_id": "n_assoc_hetero", "direction": "SUPPORTS", "claim_paragraph": {"research": "Analyses of two UK datasets (n = 84,011; longitudinal n = 17,409) identify distinct developmental windows in which higher social media use predicts lower life satisfaction a year later: ages 11-13 for girls, 14-15 for boys, and 19 for both sexes. Sensitivity is not uniform across adolescence \u2014 and the girls' window sits in early adolescence.", "simple": "In two huge UK datasets, social media predicted feeling worse a year later only at particular ages \u2014 around 11-13 for girls, 14-15 for boys, and 19 for everyone. It's not all teens equally: timing and sex matter, with young girls in the most exposed window."}, "effect_size": {"research": "negative use\u2192satisfaction prediction confined to specific age/sex windows", "simple": "real but only at certain ages, especially young girls"}, "source_type": "single-study", "source_citation": "Orben, Przybylski, Blakemore & Kievit 2022, Windows of developmental sensitivity to social media, Nature Communications 13:1649.", "triggers_split_to": [], "tension_with": ["F-mag-4"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "orben-przybylski", "caveat": {"research": "Observational; estimated (not logged) use; same research group whose specification-curve work anchors the tiny-average-association case \u2014 the two are consistent (small average, concentrated windows), not contradictory.", "simple": "Not an experiment, and from the same team that found the tiny average link \u2014 small-on-average and worse-for-some can both be true."}}, {"finding_id": "F-het-2", "node_id": "n_assoc_hetero", "direction": "SUPPORTS", "claim_paragraph": {"research": "The post-2010 rises in US adolescent depressive symptoms, suicide-related outcomes, and suicide rates are concentrated among girls, and new-media screen time is more strongly associated with mental-health problems among girls \u2014 the trend data's sex asymmetry matches the heterogeneity hypothesis.", "simple": "The rise in teen distress after 2010 hit girls hardest, and the link between social media and feeling bad is also stronger for girls. The pattern fits the idea that harms are concentrated, not spread evenly."}, "effect_size": {"research": "rises and associations concentrated among girls", "simple": "girls affected clearly more than boys"}, "source_type": "single-study", "source_citation": "Twenge, Joiner, Rogers & Martin 2018, Clinical Psychological Science 6(1):3-17.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "twenge", "caveat": {"research": "Correlational trend data; author is the most prominent proponent of the harm hypothesis \u2014 treat as one input, not a neutral referee.", "simple": "Pattern-matching over time, not an experiment \u2014 and from the leading voice on one side of this debate."}}, {"finding_id": "F-het-3", "node_id": "n_assoc_hetero", "direction": "SUPPORTS", "claim_paragraph": {"research": "Causal evidence from Norwegian school smartphone bans shows benefits concentrated exactly where the heterogeneity hypothesis predicts: reduced psychological-symptom healthcare use among girls, and GPA/exam gains for girls, strongest for low-socioeconomic-status students. Removing the exposure helped the predicted subgroups most.", "simple": "When Norwegian schools banned phones, the clearest gains \u2014 fewer mental-health visits, better grades \u2014 showed up among girls and poorer students. Taking the exposure away helped most exactly where you'd expect if harms are concentrated."}, "effect_size": {"research": "girls' math exam \u2248 +0.22 SD; psych-care visits down among girls", "simple": "girls' grades up noticeably; fewer mental-health visits for girls"}, "source_type": "single-study", "source_citation": "Abrahamsson 2024, Smartphone Bans, Student Outcomes and Mental Health, NHH Dept. of Economics Discussion Paper 01/2024 (SSRN 4735240).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "quasi-experimental", "source_cluster": "nordic-ban", "caveat": {"research": "Indirect: policy-response heterogeneity, and smartphones-in-school, not social media per se; working paper at scan date.", "simple": "It's about school phone bans, not social media directly \u2014 and not yet fully peer-reviewed."}}, {"finding_id": "F-ben-1", "node_id": "n_assoc_benefits", "direction": "SUPPORTS", "claim_paragraph": {"research": "The National Academies consensus report treats benefits as findings, not talking points: social media creates opportunities for community and support among marginalized youth \u2014 including LGBTQ+ adolescents in unsupportive environments \u2014 and provides everyday connection and enjoyment for the large majority of adolescent users.", "simple": "The big expert report is clear that social media genuinely helps some teens: kids who can't find their community where they live \u2014 including LGBTQ+ teens \u2014 find real support online, and most teens get ordinary fun and connection from it."}, "effect_size": {"research": "qualitative; strongest for marginalized youth", "simple": "real help, biggest for isolated kids"}, "source_type": "systematic-review", "source_citation": "National Academies of Sciences, Engineering, and Medicine 2024, Social Media and Adolescent Health.", "triggers_split_to": [], "tension_with": ["F-cau-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2024", "caveat": {"research": "Benefit evidence is largely qualitative and self-report; no quantitative benefit meta-analysis is cited here.", "simple": "Mostly based on what teens themselves report, not hard measurements."}}, {"finding_id": "F-ben-2", "node_id": "n_assoc_benefits", "direction": "COMPLICATES", "claim_paragraph": {"research": "The same review literature that undercuts large average harms also undercuts large average benefits: associations between use and well-being are a mix of small positive, small negative, and null. Benefits and harms plainly coexist within the same population \u2014 the honest reading is heterogeneity in both directions, not a net verdict.", "simple": "The same studies that say the average harm is small also say the average benefit is small \u2014 some teens gain, some lose, many feel nothing much either way. Help and harm live side by side; there's no single net answer."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Odgers & Jensen 2020, J. Child Psychology & Psychiatry 61:336-348.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "odgers-review", "caveat": {"research": "Narrative review; pre-2020 literature.", "simple": "Expert overview from 2020."}}, {"finding_id": "F-trd-1", "node_id": "n_trend", "direction": "COMPLICATES", "claim_paragraph": {"research": "Two claims travel together in public debate but are evidentially separate: that adolescent mental health really worsened after ~2010, and that social media caused it. The first can be true while the second is unproven \u2014 a timing coincidence plus an individual-level association is not population-level attribution. Rival explanations (economic insecurity, academic pressure, changed diagnostic practice) are rarely tested head-to-head.", "simple": "'Teen mental health got worse' and 'social media did it' are two different claims. The first can be true while the second stays unproven \u2014 things lining up in time isn't the same as one causing the other, and other suspects (money worries, school pressure) rarely get tested side by side."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Odgers & Jensen 2020, JCPP; National Academies 2024.", "triggers_split_to": ["n_trend_real", "n_trend_attrib"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "odgers-review", "caveat": {"research": "A framing, not a measurement.", "simple": "A point about logic, not a new study."}}, {"finding_id": "F-real-1", "node_id": "n_trend_real", "direction": "SUPPORTS", "claim_paragraph": {"research": "US adolescents' depressive symptoms, suicide-related outcomes, and suicide RATES all rose after 2010, especially among girls. Because the rise includes objectively recorded outcomes (suicide deaths), it cannot be fully explained by greater help-seeking, awareness, or willingness to report distress.", "simple": "After 2010, US teens didn't just say they felt worse \u2014 self-harm and suicide statistics, which don't depend on teens' willingness to talk, also rose, especially among girls. That's hard to explain as just more openness about mental health."}, "effect_size": {"research": "concurrent rises across self-report and objective series post-2010", "simple": "worse on both surveys and hard statistics"}, "source_type": "single-study", "source_citation": "Twenge, Joiner, Rogers & Martin 2018, Clinical Psychological Science 6(1):3-17; Twenge 2020, Psychiatric Research and Clinical Practice 2:19-25.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "twenge", "caveat": {"research": "US-centric; suicide statistics have their own recording issues; author is the leading proponent of the social-media explanation.", "simple": "Mostly US data, and from the strongest advocate of blaming social media."}}, {"finding_id": "F-real-2", "node_id": "n_trend_real", "direction": "SUPPORTS", "claim_paragraph": {"research": "A Norwegian study directly tested the measurement-artifact objection: the depressive-symptoms instrument was measurement-invariant across 2010-2019 (the scale meant the same thing over time), the few non-invariant parameters had negligible impact, and latent mean symptom scores genuinely rose among girls from 2014. Where the artifact hypothesis has been formally tested, the increase survived.", "simple": "Norwegian researchers checked the sceptics' favourite objection \u2014 'maybe the survey questions just mean something different to today's teens'. The questions held steady in meaning, and girls' symptoms still genuinely rose. Where the excuse was tested, it failed."}, "effect_size": {"research": "latent-mean rise among girls from 2014; invariance held", "simple": "a real rise for girls, not a survey quirk"}, "source_type": "single-study", "source_citation": "Time trends in adolescent depressive symptoms from 2010 to 2019 in Norway: real increase or artifacts of measurements?, Psychological Medicine (2024; PMC11578914).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "nordic-trend", "caveat": {"research": "One country, one instrument; the artifact hypothesis could still hold elsewhere or for other measures.", "simple": "Only Norway, only one questionnaire \u2014 other countries' numbers could still have quirks."}}, {"finding_id": "F-real-3", "node_id": "n_trend_real", "direction": "COMPLICATES", "claim_paragraph": {"research": "The artifact concern is nonetheless live: most trend studies use raw sum scores without testing whether their measures are invariant over time \u2014 a prerequisite for meaningful trend inference that the Norwegian authors note is routinely skipped. Reporting norms, screening practices, and diagnostic thresholds all changed over the same decade; how much of the international rise they explain is not settled.", "simple": "Still, most studies never check whether their survey questions kept meaning the same thing across the decade \u2014 the Norwegian team points out almost nobody tests this. Attitudes to mental health changed a lot in those years; how much of the worldwide rise that explains isn't settled."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Methodological framing in: Psychological Medicine 2024 Norway invariance study (PMC11578914).", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "nordic-trend", "caveat": {"research": "No standalone quantitative artifact-hypothesis source located under the protocol at authoring time \u2014 this caution is carried from within a pro-real-increase source; the AGAINST side of this leaf is genuinely thin.", "simple": "We couldn't find a strong study arguing the rise is fake \u2014 this doubt comes from inside a study that found the rise is real."}}, {"finding_id": "F-att-1", "node_id": "n_trend_attrib", "direction": "SUPPORTS", "claim_paragraph": {"research": "The timing and shape of the deterioration match the exposure: adolescent depressive symptoms, self-harm, and suicide rose precisely as smartphone-plus-social-media adoption saturated (post-2010/2012), the rises are concentrated among girls (the heaviest social-media users), and new-media screen time is associated with the same outcomes at the individual level. No rival explanation matches the timing, cross-national breadth, and sex pattern as well, on this argument.", "simple": "The case for blaming social media: teen distress rose exactly when smartphones and social media took over, it rose most for girls \u2014 who use social media most \u2014 and heavy users are the ones who feel worst. Supporters argue no other explanation fits the timing and the girl/boy pattern as well."}, "effect_size": {"research": "timing + sex-pattern concordance; correlational", "simple": "the timing and pattern fit \u2014 but it's circumstantial"}, "source_type": "single-study", "source_citation": "Twenge, Joiner, Rogers & Martin 2018, Clinical Psychological Science; Twenge 2020, Psychiatric Research and Clinical Practice (mechanisms review).", "triggers_split_to": [], "tension_with": ["F-cau-1", "F-att-3"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "twenge", "caveat": {"research": "Correlational timing evidence from the hypothesis's leading proponent; the FOR side of this leaf is single-cluster \u2014 flagged in the audit.", "simple": "Circumstantial evidence, mostly from one research team that champions this theory."}}, {"finding_id": "F-att-2", "node_id": "n_trend_attrib", "direction": "SUPPORTS", "claim_paragraph": {"research": "The proposed mechanisms are articulated and individually plausible: displacement of sleep and in-person interaction, upward social comparison, and cyberbullying exposure \u2014 each with its own supporting literature \u2014 jointly connecting population-level adoption to population-level distress.", "simple": "The theory also says HOW it would work: less sleep, less in-person time, constant comparison with others, and online bullying. Each piece has some evidence behind it."}, "effect_size": {"research": "qualitative (mechanism synthesis)", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Twenge 2020, Increases in Depression, Self-Harm, and Suicide Among U.S. Adolescents After 2012 and Links to Technology Use: Possible Mechanisms, Psychiatric Research and Clinical Practice 2:19-25.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "twenge", "caveat": {"research": "Mechanism plausibility is not attribution; same cluster as F-att-1 (no independent corroboration added).", "simple": "Explaining how it COULD work isn't proof it DID \u2014 and this is the same team again."}}, {"finding_id": "F-att-3", "node_id": "n_trend_attrib", "direction": "CHALLENGES", "claim_paragraph": {"research": "The National Academies consensus review examined this literature and did not support the conclusion that social media causes changes in adolescent health at the population level \u2014 the direct institutional verdict on the attribution claim, from the strongest available synthesis tier.", "simple": "The major expert committee looked at this exact question and would not endorse 'social media drove the decline'. That's the highest-level scientific review saying: not proven."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "National Academies of Sciences, Engineering, and Medicine 2024, Social Media and Adolescent Health.", "triggers_split_to": [], "tension_with": ["F-att-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2024", "caveat": {"research": "High evidentiary bar; 'not supported' is not 'refuted'.", "simple": "'Not proven' doesn't mean 'proven wrong'."}}, {"finding_id": "F-att-4", "node_id": "n_trend_attrib", "direction": "CHALLENGES", "claim_paragraph": {"research": "Scaling objection: the best-measured individual-level associations are small and bidirectionally confounded, which makes social media an underpowered candidate for PRINCIPAL driver of a large population-level deterioration without additional strong assumptions. The review literature emphasizes that correlational designs cannot distinguish cause from effect at any scale.", "simple": "The math problem: at the individual level the measured link is small. Turning a small, tangled link into 'this is the main cause of a big national decline' requires extra assumptions nobody has proven."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Odgers & Jensen 2020, J. Child Psychology & Psychiatry 61:336-348.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "odgers-review", "caveat": {"research": "An inference from association magnitudes, not a direct test of the attribution claim.", "simple": "A logical objection, not a study that directly tested the claim."}}, {"finding_id": "F-mech-1", "node_id": "n_mech", "direction": "COMPLICATES", "claim_paragraph": {"research": "Proposed harm pathways differ in testability. Sleep displacement is independently measurable and is scored below. Social comparison and algorithmic amplification are evidenced mainly INSIDE other studies \u2014 e.g. the Facebook-rollout quasi-experiment attributes part of its effect to unfavorable social comparison, and the National Academies report identifies algorithmic amplification as a plausible channel \u2014 rather than as independently scored claims with good-faith evidence on both sides.", "simple": "Of the ways social media might hurt teens, only one \u2014 costing them sleep \u2014 can be measured cleanly on its own, so only that one gets a score here. The others (comparing yourself to others, algorithms pushing harmful stuff) show up as clues inside other studies, not as separately settled questions."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Braghieri, Levy & Makarin 2022, AER (mechanism evidence); National Academies 2024 (design-feature channels).", "triggers_split_to": ["n_mech_sleep"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "econ-quasiexp", "caveat": {"research": "Scope decision recorded in this node's coverage note; mechanism claims remain visible via findings on the causal leaf.", "simple": "A choice about what this tool scores, explained in the scope note."}}, {"finding_id": "F-slp-1", "node_id": "n_mech_sleep", "direction": "SUPPORTS", "claim_paragraph": {"research": "Meta-analysis of portable screen-based device access and use in 6-19-year-olds finds strong and consistent associations with reduced sleep quantity, worse sleep quality, and daytime sleepiness \u2014 present even for device ACCESS at bedtime without measured use, consistent with both displacement and arousal channels.", "simple": "Adding up many studies of kids and teens: having or using a phone or tablet around bedtime goes with less sleep, worse sleep, and daytime tiredness \u2014 even just having the device in the room, unused, shows the pattern."}, "effect_size": {"research": "consistent adverse associations across sleep quantity, quality, daytime sleepiness", "simple": "less and worse sleep, across many studies"}, "source_type": "meta-analysis", "source_citation": "Carter, Rees, Hale, Bhattacharjee & Paradkar 2016, Association Between Portable Screen-Based Media Device Access or Use and Sleep Outcomes, JAMA Pediatrics 170(12):1202-1208.", "triggers_split_to": [], "tension_with": ["F-slp-2"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "carter-sleep-meta", "caveat": {"research": "Measures devices/screens generally, not social media specifically; correlational inputs; \u226510 years old in 2026 \u2014 flagged for refresh review under the protocol.", "simple": "About screens in general, not social media alone; from 2016, so due for a refresh."}}, {"finding_id": "F-slp-2", "node_id": "n_mech_sleep", "direction": "CHALLENGES", "claim_paragraph": {"research": "A 2026 meta-analysis of WITHIN-PERSON designs \u2014 comparing the same young person's high-screen and low-screen days \u2014 finds only a small association between daily screen time and later sleep onset, and minimal impact on sleep duration, efficiency, or quality. Day-to-day, screens delay bedtime slightly but do not degrade sleep the way between-person comparisons imply.", "simple": "A newer approach follows the SAME teen across days: on heavier-screen days they fall asleep a bit later, but their sleep isn't much shorter or worse. Comparing a teen to themselves shows a far smaller effect than comparing screen-heavy teens to screen-light ones."}, "effect_size": {"research": "small within-person delay in sleep onset; minimal effect on duration/efficiency/quality", "simple": "slightly later bedtime; sleep itself barely changed"}, "source_type": "meta-analysis", "source_citation": "Bourke et al. 2026, Within-Person Association Between Daily Screen Use and Sleep in Youth: A Systematic Review and Meta-Analysis, JAMA Pediatrics (May 2026).", "triggers_split_to": [], "tension_with": ["F-slp-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "uq-withinperson-meta", "caveat": {"research": "Within-person daily fluctuation is a different estimand from chronic heavy use: a stable heavy user shows no day-to-day variation to detect. Both metas can be right about different questions.", "simple": "This measures day-to-day changes \u2014 it can miss harm from ALWAYS-heavy use. Both results can be true at once."}}, {"finding_id": "F-pol-1", "node_id": "n_policy", "direction": "COMPLICATES", "claim_paragraph": {"research": "The three restriction families differ enormously in dose, scope, and enforceability: a school phone ban removes a few school-hours of one device; personal deactivation removes weeks of individual exposure while the peer network stays online; a national age ban attempts population-wide removal against circumvention incentives. Evidence for one does not license expectations about another \u2014 and evidence that HARM exists does not by itself establish that any given restriction reduces it.", "simple": "'Ban it' means three very different things: phones out of school hours, one person quitting for a while, or a whole country's age limit. Each works differently and each can fail differently \u2014 and proving social media harms teens still doesn't prove a particular ban will fix it."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "National Academies 2024 (policy discussion); design contrast across Abrahamsson 2024, Allcott et al. 2020, Barnes et al. 2026.", "triggers_split_to": ["n_policy_school", "n_policy_deact", "n_policy_ban"], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "NAS-2024", "caveat": {"research": "A framing of intervention heterogeneity, not a measurement.", "simple": "A point about comparing apples to oranges."}}, {"finding_id": "F-sch-1", "node_id": "n_policy_school", "direction": "SUPPORTS", "claim_paragraph": {"research": "Exploiting staggered ban adoption across 477 Norwegian middle schools (2010-2018) linked to national registry data: smartphone bans significantly reduced healthcare consultations for psychological symptoms among girls, reduced bullying for both sexes, and raised girls' GPA and externally graded math results (\u2248 +0.22 SD), with the largest gains for low-SES students.", "simple": "In Norway, researchers compared hundreds of schools that banned phones at different times, using national health and school records. After bans: fewer mental-health visits for girls, less bullying for everyone, and better grades for girls \u2014 with the poorest students gaining most."}, "effect_size": {"research": "girls' math \u2248 +0.22 SD; psych-consultations and bullying down", "simple": "clearly better grades and fewer mental-health visits, mainly for girls"}, "source_type": "single-study", "source_citation": "Abrahamsson 2024, Smartphone Bans, Student Outcomes and Mental Health, NHH Discussion Paper 01/2024 (SSRN 4735240).", "triggers_split_to": [], "tension_with": ["F-sch-3"], "source_strength": "moderate", "evidence_type": "quasi-experimental", "source_cluster": "nordic-ban", "caveat": {"research": "Working paper (not yet peer-reviewed at scan date); ban timing from retrospective school-leader surveys; Norway-specific institutions.", "simple": "Not yet fully peer-reviewed, and schools reported their own ban dates from memory."}}, {"finding_id": "F-sch-2", "node_id": "n_policy_school", "direction": "SUPPORTS", "claim_paragraph": {"research": "Quasi-experimental evidence from a large Florida district's September 2023 cellphone ban: student phone use fell by about two-thirds, and test scores rose by roughly 1.1-1.3 percentage points within two years, with effects concentrated in middle/high school. Costs were real but transient: suspensions spiked in the first year (disproportionately among Black students) before dissipating.", "simple": "In a big Florida school district that banned phones in 2023, phone use fell by about two-thirds and test scores rose modestly within two years. The downside: suspensions jumped at first \u2014 hitting Black students hardest \u2014 before settling back down."}, "effect_size": {"research": "test scores +1.1-1.3 pp; use down ~2/3; transient suspension spike", "simple": "modestly better scores; a rocky first year of discipline"}, "source_type": "single-study", "source_citation": "Figlio & \u00d6zek 2025, The Impact of Cellphone Bans in Schools on Student Outcomes: Evidence from Florida, NBER Working Paper 34388.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "quasi-experimental", "source_cluster": "nber-florida", "caveat": {"research": "Working paper; academic outcomes, with mental health not directly measured; one district.", "simple": "Not yet peer-reviewed, one district, and it measured grades more than feelings."}}, {"finding_id": "F-sch-3", "node_id": "n_policy_school", "direction": "CHALLENGES", "claim_paragraph": {"research": "The SMART Schools study \u2014 1,227 adolescents across 30 English secondary schools \u2014 found no significant difference in mental wellbeing, sleep, or attainment between schools with restrictive and permissive phone policies, and no difference in total phone/social-media time across the whole day: students compensated outside school hours.", "simple": "In England, researchers compared 30 schools with strict and relaxed phone rules: the students felt the same, slept the same, and performed the same \u2014 because a school-hours ban barely changed their TOTAL daily phone time. They caught up after the bell."}, "effect_size": {"research": "no significant policy-level differences in wellbeing, sleep, attainment", "simple": "no difference between strict and relaxed schools"}, "source_type": "single-study", "source_citation": "Goodyear et al. 2025, School phone policies and their association with mental wellbeing, phone use, and social media use (SMART Schools), The Lancet Regional Health - Europe.", "triggers_split_to": [], "tension_with": ["F-sch-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "smart-schools", "caveat": {"research": "Cross-sectional (no ban-timing identification); compares POLICY, i.e. a few school-hours of exposure difference \u2014 a null here is consistent with total-use effects and with the Norwegian causal design finding benefits.", "simple": "A snapshot comparison, not a before-and-after \u2014 and school rules only touch a slice of the day, so this doesn't contradict bans changing more than that slice."}}, {"finding_id": "F-sch-4", "node_id": "n_policy_school", "direction": "COMPLICATES", "claim_paragraph": {"research": "The headline disagreement is largely a design-and-dose artifact: causal ban-timing studies (Norway, Florida) find benefits; the cross-sectional English policy comparison finds none. School policies alter a minority share of daily exposure, so studies contrasting school POLICY test a much weaker treatment than studies tracking actual behavior change \u2014 commentary in the same journal argues policy needs to go beyond school-hours restriction.", "simple": "The 'it works' and 'no difference' headlines aren't really fighting: the studies that tracked what actually changed found benefits, while the snapshot compared rules that barely dent a teen's total phone day. Even the journal that published the null says school rules alone are too small a lever."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Smartphone use and mental health: going beyond school restriction policies, The Lancet Regional Health - Europe 2025 (commentary; PMC11850730).", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "lancet-commentary", "caveat": {"research": "Commentary/interpretation, not new data.", "simple": "An expert's argument, not a new study."}}, {"finding_id": "F-dea-1", "node_id": "n_policy_deact", "direction": "SUPPORTS", "claim_paragraph": {"research": "In the landmark randomized experiment (n \u2248 2,743 adults), four weeks of Facebook deactivation before the 2018 US midterms increased subjective well-being, increased offline socializing, reduced political polarization, and produced a persistent post-experiment reduction in Facebook use \u2014 the cleanest early evidence that removal improves measured well-being.", "simple": "In the classic experiment, people paid to turn off Facebook for a month felt better, saw friends and family more, and were less politically angry. Many kept using it less even after the experiment ended."}, "effect_size": {"research": "positive SWB effect of 4-week deactivation", "simple": "a real, modest boost from a month off"}, "source_type": "single-study", "source_citation": "Allcott, Braghieri, Eichmeyer & Gentzkow 2020, The Welfare Effects of Social Media, American Economic Review 110(3).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "experimental", "source_cluster": "allcott-gentzkow", "caveat": {"research": "Adults, one platform, pre-election period; payment-induced deactivation may not generalize to voluntary reduction.", "simple": "Adults, not teens \u2014 and being paid to quit isn't quite the same as choosing to."}}, {"finding_id": "F-dea-2", "node_id": "n_policy_deact", "direction": "SUPPORTS", "claim_paragraph": {"research": "The largest deactivation experiment to date (~19,900 Facebook and ~15,500 Instagram users, six weeks around the 2020 US election) found deactivation improved an emotional-state index by 0.060 SD (Facebook) and 0.041 SD (Instagram) \u2014 small but precisely estimated gains, roughly 15-22% of the effect of a typical psychological intervention.", "simple": "In the biggest experiment yet \u2014 35,000 people off Facebook or Instagram for six weeks \u2014 people's mood improved by a small but reliably measured amount: roughly a fifth of what a course of therapy typically does."}, "effect_size": {"research": "+0.060 SD (Facebook), +0.041 SD (Instagram) emotional state", "simple": "small but real mood gains"}, "source_type": "single-study", "source_citation": "Allcott, Gentzkow et al. 2025, The Effect of Deactivating Facebook and Instagram on Users' Emotional State, NBER Working Paper 33697.", "triggers_split_to": [], "tension_with": ["F-dea-3", "F-ban-2"], "source_strength": "moderate", "evidence_type": "experimental", "source_cluster": "allcott-gentzkow", "caveat": {"research": "Working paper; adults; election-period context; same core research team as F-dea-1 \u2014 one cluster, not independent corroboration.", "simple": "Adults again, around a heated election, and by the same research team as the first experiment."}}, {"finding_id": "F-dea-3", "node_id": "n_policy_deact", "direction": "CHALLENGES", "claim_paragraph": {"research": "A preregistered systematic review and meta-analysis of social media ABSTINENCE interventions (10 studies, n = 4,674, 38 effect sizes) found no significant effects on positive affect, negative affect, or life satisfaction \u2014 and no relationship between abstinence duration and outcomes. Pooled across the abstinence literature, taking a break does not measurably improve well-being.", "simple": "But when researchers pooled ten studies of people taking social media breaks \u2014 nearly 5,000 people \u2014 the breaks didn't significantly improve mood or life satisfaction at all, no matter how long they lasted."}, "effect_size": {"research": "no significant pooled effect on affect or life satisfaction", "simple": "no measurable benefit on average"}, "source_type": "meta-analysis", "source_citation": "Lemahieu et al. 2025, The effects of social media abstinence on affective well-being and life satisfaction: a systematic review and meta-analysis, Scientific Reports 15 (s41598-025-90984-3).", "triggers_split_to": [], "tension_with": ["F-dea-2"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "antwerp-abstinence-meta", "caveat": {"research": "Mostly small, short-duration studies of young adults; the large Allcott-Gentzkow deactivation RCTs are a different (payment-incentivized, longer) design and partly postdate the search window.", "simple": "Mostly small, short studies of young adults \u2014 the giant six-week experiments were run differently and some came later."}}, {"finding_id": "F-dea-4", "node_id": "n_policy_deact", "direction": "CHALLENGES", "claim_paragraph": {"research": "The Ferguson meta-analysis of 27 reduction/exposure experiments likewise reports a pooled effect (d \u2248 0.09) whose confidence interval includes zero, concluding experimental reductions in social media use show no reliable average mental-health benefit.", "simple": "Another round-up of 27 cut-back experiments also found an average benefit so small it might be zero."}, "effect_size": {"research": "pooled d \u2248 0.09, CI includes zero", "simple": "possibly zero on average"}, "source_type": "meta-analysis", "source_citation": "Ferguson 2024, Do social media experiments prove a link with mental health, Psychology of Popular Media.", "triggers_split_to": [], "tension_with": ["F-dea-5"], "source_strength": "thin", "evidence_type": "review", "source_cluster": "reduction-rct-pool", "caveat": {"research": "DISPUTED (see F-cau-4): alleged data errors and contested pooling of heterogeneous designs/durations; read only alongside F-dea-5, which reanalyzes the same pool.", "simple": "Contested \u2014 critics found errors, and a re-check of the same experiments reached a different conclusion (next card)."}}, {"finding_id": "F-dea-5", "node_id": "n_policy_deact", "direction": "COMPLICATES", "claim_paragraph": {"research": "A 2025 reanalysis of the same experimental pool, testing moderation by intervention length, finds social-media reduction or abstinence DOES provide mental-health benefits \u2014 the null average masks a duration gradient in which longer interventions show benefits. The same data support 'no effect' or 'real benefit' depending on whether duration is modeled.", "simple": "When other researchers re-ran the numbers on those same experiments, they found the breaks DO help \u2014 mainly the longer ones. Whether the experiments say 'no effect' or 'real benefit' depends on whether you account for how long the break lasted."}, "effect_size": {"research": "benefits emerge with longer intervention duration", "simple": "longer breaks help; short ones don't show much"}, "source_type": "meta-analysis", "source_citation": "Social Media Reduction or Abstinence Interventions Are Providing Mental Health Benefits - Reanalysis of a Published Meta-Analysis, Psychology of Popular Media (2025).", "triggers_split_to": [], "tension_with": ["F-dea-4"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "reduction-rct-pool", "caveat": {"research": "Same underlying study pool as F-dea-4 (shared cluster \u2014 no independent corroboration between them); reanalysis is itself one team's modeling choice.", "simple": "It re-uses the same experiments as the round-up it corrects, so they count as one body of evidence, not two."}}, {"finding_id": "F-ban-1", "node_id": "n_policy_ban", "direction": "CHALLENGES", "claim_paragraph": {"research": "The first evaluation of Australia's under-16 Social Media Minimum Age Act (408 adolescents aged 12-16 surveyed immediately before and three months after commencement) found no clear short-term reduction in use: over 86% of under-16s had accessed at least one platform post-ban, 54-68% via their own accounts, with circumvention (borrowed accounts, fake ages, private browsers) widespread and age checks easily bypassed.", "simple": "Three months into Australia's world-first under-16 ban, more than 86% of under-16s were still on social media. Kids used borrowed accounts, fake birthdates, and private browsers; age checks were easy to beat."}, "effect_size": {"research": ">86% of under-16s still accessing platforms at 3 months; little change at 12-13, slight decrease at 14-15", "simple": "almost everyone still on; barely a dent"}, "source_type": "single-study", "source_citation": "Barnes et al. 2026, Assessing early effects of Australia's Social Media Minimum Age Act on adolescents' social media use: observational study, BMJ (published 24 June 2026).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "aus-ban-eval", "caveat": {"research": "Small single cohort, self-report, three-month window during a chaotic rollout with incomplete platform compliance; measures use, not mental health.", "simple": "One smallish survey, only three months in, while enforcement was still leaky \u2014 and it measured use, not how kids felt."}}, {"finding_id": "F-ban-2", "node_id": "n_policy_ban", "direction": "COMPLICATES", "claim_paragraph": {"research": "No qualifying FOR evidence exists at authoring time: the case that age bans reduce use (and downstream harm) currently rests on policy expectation, not measured results \u2014 and symmetrically, the early Australian null must not be over-read. It covers one quarter of a leaky rollout and measures use only; it is not evidence about the mental-health effects of a mature, enforced ban, in either direction.", "simple": "Fair warning in both directions: there's no measured evidence yet that bans DO keep kids off or make them feel better \u2014 but three messy early months also can't prove bans DON'T work. On the big question \u2014 does a real, enforced ban improve teen mental health \u2014 nobody has data yet."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Limitations discussion in Barnes et al. 2026, BMJ; no qualifying FOR-direction source located under the sourcing protocol at authoring time.", "triggers_split_to": [], "tension_with": ["F-dea-2"], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "aus-ban-eval", "caveat": {"research": "The FOR slot of this leaf is deliberately empty rather than padded \u2014 per protocol, absence of qualifying evidence is stated, not papered over.", "simple": "We left the 'bans work' side blank on purpose \u2014 there was no solid study to put there yet."}}], "tensions": [{"a": "F-mag-4", "b": "F-cau-1", "kind": "assumption-sensitivity", "note": {"research": "Tiny cross-sectional variance-explained vs a real quasi-experimental adoption effect \u2014 different estimands answering different questions; which one 'the effect of social media' means is an assumption, not a finding.", "simple": "One study says the everyday link is tiny; another says Facebook's arrival genuinely hurt. They measure different things \u2014 both can be right."}}, {"a": "F-mag-1", "b": "F-mag-4", "kind": "scope-aggregation", "note": {"research": "Moderate correlations for the 'problematic use' construct vs near-zero variance for time-spent measures \u2014 the construct choice, not the data, drives the headline magnitude.", "simple": "Measure compulsive-style use and the link looks real; measure plain hours and it looks tiny. The choice of yardstick makes the headline."}}, {"a": "F-het-1", "b": "F-mag-4", "kind": "scope-aggregation", "note": {"research": "Concentrated age/sex windows of sensitivity vs a tiny population average \u2014 same research group, both results: averages can hide the subgroups. Aggregation level, not contradiction.", "simple": "The average across all teens is tiny, but certain ages \u2014 especially young girls \u2014 show real effects. The average hides the hotspots; same team found both."}}, {"a": "F-att-1", "b": "F-cau-1", "kind": "scope-aggregation", "note": {"research": "An individual-level causal effect (college Facebook rollout) does not scale by itself into 'principal driver of the population trend' \u2014 the central conflation this map exists to keep apart.", "simple": "Proving social media hurt some students is not the same as proving it caused the whole national decline. The jump between those two is where the debate cheats."}}, {"a": "F-att-1", "b": "F-att-3", "kind": "empirical-contradiction", "note": {"research": "The timing-and-pattern attribution case vs the National Academies' refusal to endorse population-level causation \u2014 a genuine live dispute about the same claim.", "simple": "One side says the timing and pattern prove it; the top expert committee says it isn't proven. They genuinely disagree."}}, {"a": "F-slp-1", "b": "F-slp-2", "kind": "assumption-sensitivity", "note": {"research": "Between-person device/sleep associations are consistently adverse; within-person day-to-day designs find little beyond a small onset delay. The design choice (who is compared to whom) largely determines the answer.", "simple": "Compare screen-heavy kids to screen-light kids: sleep looks worse. Compare the same kid's heavy and light days: barely a difference. How you compare decides what you find."}}, {"a": "F-sch-1", "b": "F-sch-3", "kind": "context-transportability", "note": {"research": "Norwegian causal ban-timing benefits vs English cross-sectional policy null \u2014 different countries, designs, and effective doses (registry-linked ban rollout vs school-hours policy snapshot). Not a like-for-like clash.", "simple": "Norway's before-and-after study found benefits; England's snapshot found none. Different countries, different methods, different strictness \u2014 not a head-to-head fight."}}, {"a": "F-dea-2", "b": "F-dea-3", "kind": "empirical-contradiction", "note": {"research": "The largest deactivation RCTs find small precise emotional-state gains; the abstinence meta-analysis pools to null. A genuine dispute about whether short-run removal helps \u2014 durations, designs, and samples differ.", "simple": "The biggest experiments say a six-week break helps a little; a round-up of smaller studies says breaks don't help at all. A real disagreement."}}, {"a": "F-dea-4", "b": "F-dea-5", "kind": "scope-aggregation", "note": {"research": "Same experimental pool, opposite headlines: pooled-average null vs benefits once intervention length is modeled. The aggregation choice, not new data, flips the conclusion.", "simple": "Same experiments, two conclusions: 'no effect' when you average everything, 'longer breaks help' when you sort by length. The math choice flips the answer."}}, {"a": "F-ben-1", "b": "F-cau-1", "kind": "cross-dimension", "note": {"research": "Documented benefits (community for marginalized youth) and documented causal harm (social-comparison effects) coexist and CANNOT be netted empirically \u2014 how to weigh them across different adolescents is a value choice.", "simple": "Social media genuinely helps some teens and genuinely hurt others. Those don't cancel out into one number \u2014 how to weigh them is a judgement call, not a fact."}}, {"a": "F-ban-2", "b": "F-dea-2", "kind": "context-transportability", "note": {"research": "Individual deactivation gains do not predict population age-ban effects: a ban changes the whole peer network's equilibrium (or fails via circumvention), which no individual-level RCT can estimate.", "simple": "One person quitting for six weeks tells you little about banning a whole age group \u2014 a real ban changes what ALL the kids' friends are doing, or gets dodged entirely."}}]};

const STR_RANK = { strong: 0, moderate: 1, thin: 2 };
const DIR_LABEL = { SUPPORTS: "FOR", CHALLENGES: "AGAINST", COMPLICATES: "COMPLICATES" };
const DIR_COLOR = { SUPPORTS: "#5c7a64", CHALLENGES: "#a85d52", COMPLICATES: "#9a8a55" };
const TEASER_KINDS = new Set(["cross-dimension", "empirical-contradiction"]);

function buildIndex(d) {
  const nodeById = {}; d.nodes.forEach(n => (nodeById[n.id] = n));
  const findingById = {}; d.findings.forEach(f => (findingById[f.finding_id] = f));
  const findingsByNode = {};
  d.findings.forEach(f => { (findingsByNode[f.node_id] ||= []).push(f); });
  const subtree = {};
  const collect = (id) => {
    if (subtree[id]) return subtree[id];
    const set = new Set((findingsByNode[id] || []).map(f => f.finding_id));
    (nodeById[id].children || []).forEach(c => collect(c).forEach(x => set.add(x)));
    return (subtree[id] = set);
  };
  d.nodes.forEach(n => collect(n.id));
  const tnAdj = {};
  d.tensions.forEach(t => {
    (tnAdj[t.a] ||= []).push({ partner: t.b, kind: t.kind, note: t.note });
    (tnAdj[t.b] ||= []).push({ partner: t.a, kind: t.kind, note: t.note });
  });
  return { nodeById, findingById, findingsByNode, subtree, tnAdj };
}

function orderFindings(list) {
  const rank = f => (STR_RANK[f.source_strength] ?? 1);
  const tag = list.map((f, i) => ({ f, i }));
  const by = (a, b) => rank(a.f) - rank(b.f) || a.i - b.i;
  const S = tag.filter(x => x.f.direction === "SUPPORTS").sort(by);
  const C = tag.filter(x => x.f.direction === "CHALLENGES").sort(by);
  const X = tag.filter(x => x.f.direction === "COMPLICATES").sort(by);
  const inter = []; let i = 0;
  while (i < S.length || i < C.length) { if (i < S.length) inter.push(S[i]); if (i < C.length) inter.push(C[i]); i++; }
  return [...inter, ...X].map(x => x.f);
}

const pick = (x, reg) => (x && typeof x === "object" && !Array.isArray(x) && ("research" in x))
  ? (x[reg] ?? x.research) : x;

const crumb = (n, reg) => n.role === "topic" ? "Start"
  : pick(n.question, reg).replace(/\?+$/, "").replace(/^(How|Does|What|Are|Do)\s+/i, "").trim().slice(0, 24);

export default function App() {
  const idx = useMemo(() => buildIndex(DATA), []);
  const { nodeById, findingById, findingsByNode, subtree, tnAdj } = idx;

  const [current, setCurrent] = useState("n_root");
  const [reg, setReg] = useState("research");
  const P = x => pick(x, reg);
  const [path, setPath] = useState(["n_root"]);
  const [phase, setPhase] = useState("reading");
  const [step, setStep] = useState(0);
  const [seen, setSeen] = useState({});
  const [conf, setConf] = useState({});
  const [, setChoices] = useState({});
  const [visited, setVisited] = useState({ n_root: true });
  const [teasers, setTeasers] = useState(null);
  const [pendingChild, setPendingChild] = useState(null);
  const [slider, setSlider] = useState(50);

  const node = nodeById[current];
  const ordered = useMemo(() => orderFindings(findingsByNode[current] || []), [current]);

  useEffect(() => {
    if (phase === "reading" && ordered[step]) {
      const fid = ordered[step].finding_id;
      setSeen(s => (s[fid] ? s : { ...s, [fid]: true }));
    }
  }, [current, phase, step, ordered]);

  function enter(nodeId, newPath) {
    const n = nodeById[nodeId];
    setCurrent(nodeId); setPath(newPath); setStep(0); setTeasers(null); setPendingChild(null);
    setVisited(v => (v[nodeId] ? v : { ...v, [nodeId]: true }));
    if (n.scored) {
      const c = conf[nodeId] || {};
      if (c.posterior != null) setPhase("stop");
      else if (c.prior != null) setPhase("reading");
      else { setPhase("prior"); setSlider(50); }
    } else {
      const comps = (findingsByNode[nodeId] || []).filter(f => f.direction === "COMPLICATES");
      setPhase(comps.every(f => seen[f.finding_id]) ? "depend" : "reading");
    }
  }

  function next() {
    if (step < ordered.length - 1) { setStep(step + 1); return; }
    if (node.scored) { setPhase("posterior"); setSlider(Math.round(((conf[current]?.prior) ?? 0.5) * 100)); }
    else setPhase("depend");
  }

  function chooseChild(childId) {
    setChoices(c => ({ ...c, [current]: childId }));
    const sibs = (node.children || []).filter(c => c !== childId);
    const seenIds = Object.keys(seen);
    const ts = [];
    sibs.forEach(sib => {
      const sf = subtree[sib] || new Set();
      seenIds.forEach(sid => (tnAdj[sid] || []).forEach(adj => {
        if (sf.has(adj.partner) && TEASER_KINDS.has(adj.kind))
          ts.push({ sibling: sib, label: nodeById[sib].question, note: adj.note, seenId: sid });
      }));
    });
    const uniq = [...new Map(ts.map(t => [t.sibling + t.note, t])).values()];
    if (uniq.length) { setTeasers(uniq); setPendingChild(childId); setPhase("teaser"); }
    else enter(childId, [...path, childId]);
  }

  const firedFor = fid => (tnAdj[fid] || []).filter(a => seen[a.partner] && a.partner !== fid);

  const seenCount = Object.keys(seen).length;
  const viewKey = current + "|" + phase + "|" + step + "|" + reg;

  // ---------- styles ----------
  const C = { bg: "#FAFAF8", ink: "#1b1a17", mut: "#9a978f", faint: "#c9c6bd", rule: "#e8e6df" };
  const serif = "Georgia, 'Times New Roman', serif";
  const mono = "ui-monospace, 'SF Mono', Menlo, monospace";
  const wrap = { minHeight: "100vh", background: C.bg, color: C.ink, display: "flex", flexDirection: "column", alignItems: "center", padding: "28px 20px 56px", boxSizing: "border-box" };
  const col = { width: "100%", maxWidth: 560, display: "flex", flexDirection: "column", alignItems: "center", textAlign: "center", flex: 1 };
  const label = { fontFamily: mono, fontSize: 11, letterSpacing: "0.16em", textTransform: "uppercase", color: C.mut };
  const claim = { fontFamily: serif, fontSize: 21, lineHeight: 1.5, margin: "18px 0 0", maxWidth: 520 };
  const small = { fontFamily: mono, fontSize: 11.5, color: C.mut, lineHeight: 1.6 };
  const btn = { fontFamily: mono, fontSize: 12, letterSpacing: "0.06em", padding: "11px 26px", borderRadius: 999, border: "1px solid " + C.ink, background: "transparent", color: C.ink, cursor: "pointer", marginTop: 30 };
  const linkBtn = { fontFamily: mono, fontSize: 11.5, color: C.mut, background: "none", border: "none", cursor: "pointer", letterSpacing: "0.04em" };

  function Slider(onCommit, priorMark) {
    return (
      <div style={{ width: "100%", maxWidth: 380, marginTop: 26 }}>
        <div style={{ fontFamily: serif, fontSize: 40, lineHeight: 1 }}>{slider}<span style={{ fontSize: 18, color: C.mut }}>%</span></div>
        {priorMark != null && <div style={{ ...small, marginTop: 4 }}>you arrived at {Math.round(priorMark * 100)}%</div>}
        <input type="range" min="0" max="100" value={slider} onChange={e => setSlider(+e.target.value)} className="bue-range" style={{ width: "100%", marginTop: 18 }} />
        <div style={{ display: "flex", justifyContent: "space-between", ...label, fontSize: 10 }}>
          <span>certainly false</span><span>certainly true</span>
        </div>
        <button className="bue-btn" style={btn} onClick={onCommit}>Continue</button>
      </div>
    );
  }

  function Finding(f) {
    const fired = firedFor(f.finding_id);
    return (
      <>
        <div style={{ ...label, color: DIR_COLOR[f.direction], display: "flex", gap: 8, justifyContent: "center", alignItems: "center" }}>
          <span style={{ width: 6, height: 6, borderRadius: 6, background: DIR_COLOR[f.direction], display: "inline-block" }} />
          {DIR_LABEL[f.direction]} · {f.evidence_type} · {f.source_strength}
        </div>
        <p style={claim}>{P(f.claim_paragraph)}</p>
        {P(f.effect_size) && P(f.effect_size) !== "qualitative" && <div style={{ ...small, marginTop: 12 }}>{P(f.effect_size)}</div>}
        <div style={{ ...small, fontStyle: "italic", marginTop: 12, maxWidth: 460 }}>{P(f.caveat)}</div>
        <div style={{ ...small, marginTop: 10, color: C.faint }}>{f.source_citation}</div>
        {fired.map((t, i) => (
          <div key={i} style={{ marginTop: 22, paddingTop: 16, borderTop: "1px solid " + C.rule, maxWidth: 460 }}>
            <div style={{ ...label, color: C.ink }}>tension · {t.kind}</div>
            <div style={{ fontFamily: serif, fontSize: 15, lineHeight: 1.5, marginTop: 8, color: "#444" }}>{P(t.note)}</div>
          </div>
        ))}
        <button className="bue-btn" style={btn} onClick={next}>{step < ordered.length - 1 ? "Next" : (node.scored ? "Rate again" : "So it depends →")}</button>
      </>
    );
  }

  function Heading() {
    if (node.role === "topic") return null;
    if (node.scored) return (
      <>
        <div style={{ ...small, marginBottom: 6 }}>{P(node.question)}</div>
        <div style={{ fontFamily: serif, fontSize: 23, lineHeight: 1.45, maxWidth: 520 }}>{P(node.claim_evaluated)}</div>
      </>
    );
    return <div style={{ fontFamily: serif, fontSize: 23, lineHeight: 1.45, maxWidth: 520 }}>{P(node.question)}</div>;
  }

  // ---------- body per phase ----------
  let body;
  if (phase === "reading") {
    body = <>
      {current === "n_root" && step === 0 && (
        <div style={{ marginBottom: 26 }}>
          <div style={{ fontFamily: serif, fontSize: 26, lineHeight: 1.35, maxWidth: 480 }}>A place to test a belief against the evidence.</div>
          <div style={{ ...small, marginTop: 16, maxWidth: 440, lineHeight: 1.7 }}>It won't hand you a verdict. It shows what the research says, where it's thin, and where it pulls in different directions — you do the believing.</div>
          <div style={{ ...small, marginTop: 16, maxWidth: 440, color: C.faint }}>Leaves out: housing, public-service load, gains to employers, origin-country effects, politics. Absence is scope, not proof of no effect.</div>
        </div>
      )}
      {current !== "n_root" && Heading()}
      <div style={{ height: 14 }} />
      {ordered[step] && Finding(ordered[step])}
    </>;
  } else if (phase === "depend") {
    const opts = node.children || [];
    const exploredN = opts.filter(cid => visited[cid]).length;
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 30 }}>It depends. On what?</div>
      <div style={{ ...small, marginTop: 6 }}>Pick the aspect that matters most to you — the choice itself is telling.</div>
      {exploredN > 0 && <div style={{ ...small, marginTop: 4, color: C.faint }}>You've explored {exploredN} of {opts.length}.</div>}
      <div style={{ marginTop: 22, width: "100%", maxWidth: 460 }}>
        {opts.map(cid => {
          const vis = !!visited[cid];
          const post = conf[cid] && conf[cid].posterior;
          const tag = vis ? (post != null ? "visited · you left it at " + Math.round(post * 100) + "%" : "visited") : null;
          return (
            <button key={cid} className={"bue-choice" + (vis ? " bue-visited" : "")} onClick={() => chooseChild(cid)}>
              <span>
                <span className="bue-qtext">{P(nodeById[cid].question)}</span>
                {nodeById[cid].evidence_quality === "thin" && <span style={{ ...label, display: "block", marginTop: 5, color: C.faint }}>empirically thin</span>}
                {tag && <span className="bue-visited-tag">{tag}</span>}
              </span>
              <span className="bue-arrow">{vis ? "↺" : "→"}</span>
            </button>
          );
        })}
      </div>
    </>;
  } else if (phase === "teaser") {
    body = <>
      <div style={{ ...label }}>before you narrow</div>
      <div style={{ fontFamily: serif, fontSize: 21, lineHeight: 1.5, marginTop: 16, maxWidth: 500 }}>
        What you've seen pulls against evidence you're about to leave behind.
      </div>
      {teasers.map((t, i) => (
        <div key={i} style={{ marginTop: 20, maxWidth: 460 }}>
          <div style={{ ...label, color: C.ink }}>under → {crumb(nodeById[t.sibling], reg)}</div>
          <div style={{ fontFamily: serif, fontSize: 15, lineHeight: 1.5, marginTop: 8, color: "#444" }}>{P(t.note)}</div>
        </div>
      ))}
      <div style={{ ...small, marginTop: 22 }}>You can come back to it later — nothing you've read is lost.</div>
      <button className="bue-btn" style={btn} onClick={() => enter(pendingChild, [...path, pendingChild])}>Continue →</button>
    </>;
  } else if (phase === "prior") {
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 28 }}>before the evidence</div>
      <div style={{ ...small, marginTop: 6 }}>How true does this feel right now?</div>
      {Slider(() => { setConf(c => ({ ...c, [current]: { ...(c[current] || {}), prior: slider / 100 } })); setPhase("reading"); setStep(0); })}
    </>;
  } else if (phase === "posterior") {
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 28 }}>now, having read it</div>
      {Slider(() => { setConf(c => ({ ...c, [current]: { ...(c[current] || {}), posterior: slider / 100 } })); setPhase("stop"); }, conf[current]?.prior)}
    </>;
  } else if (phase === "stop") {
    const c = conf[current] || {};
    const d = c.posterior != null && c.prior != null ? Math.round((c.posterior - c.prior) * 100) : null;
    const seenHere = (findingsByNode[current] || []).map(f => f.finding_id);
    const tens = [];
    seenHere.forEach(fid => firedFor(fid).forEach(t => tens.push(t)));
    const uniqT = [...new Map(tens.map(t => [P(t.note), t])).values()];
    const parentFork = [...path].reverse().find(id => !nodeById[id].scored);
    const depObj = node.depends_on;
    const isLeafStop = depObj && (depObj.research || "").startsWith("LEAF");
    body = <>
      {Heading()}
      <div style={{ marginTop: 26, paddingTop: 20, borderTop: "1px solid " + C.rule, maxWidth: 480 }}>
        <div style={{ ...label }}>where the research runs out</div>
        <div style={{ fontFamily: serif, fontSize: 16, lineHeight: 1.6, marginTop: 12, color: "#3a3a36" }}>
          {isLeafStop
            ? P(depObj).replace(/^LEAF:\s*/, "")
            : "This is the edge of what the evidence settles. What's left is a judgment about how much weight to give each piece — a values question, not an empirical one."}
        </div>
      </div>
      {d != null && (
        <div style={{ marginTop: 24 }}>
          <div style={{ ...label }}>your move</div>
          <div style={{ fontFamily: serif, fontSize: 22, marginTop: 8 }}>
            {Math.round(c.prior * 100)}% <span style={{ color: C.mut }}>→</span> {Math.round(c.posterior * 100)}%
          </div>
          <div style={{ ...small, marginTop: 4 }}>{d === 0 ? "held steady" : (d > 0 ? "+" : "") + d + " points"}</div>
        </div>
      )}
      {uniqT.length > 0 && (
        <div style={{ marginTop: 24, maxWidth: 460 }}>
          <div style={{ ...label }}>still unresolved</div>
          {uniqT.map((t, i) => <div key={i} style={{ fontFamily: serif, fontSize: 14.5, lineHeight: 1.5, marginTop: 10, color: "#555" }}>{P(t.note)}</div>)}
        </div>
      )}
      <div style={{ marginTop: 30, display: "flex", gap: 22 }}>
        {parentFork && parentFork !== current &&
          <button className="bue-link" onClick={() => { const i = path.indexOf(parentFork); enter(parentFork, path.slice(0, i + 1)); }}>← explore another branch</button>}
      </div>
    </>;
  }

  return (
    <div style={wrap}>
      <style>{`
        @keyframes bueEnter { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: none; } }
        .bue-fade { animation: bueEnter .44s cubic-bezier(.2,.7,.2,1) both; }
        @media (prefers-reduced-motion: reduce) { .bue-fade { animation: none; } }
        .bue-range { -webkit-appearance: none; appearance: none; height: 2px; background: ${C.faint}; outline: none; border-radius: 2px; }
        .bue-range::-webkit-slider-thumb { -webkit-appearance: none; width: 18px; height: 18px; border-radius: 50%; background: ${C.ink}; cursor: pointer; }
        .bue-range::-moz-range-thumb { width: 18px; height: 18px; border: none; border-radius: 50%; background: ${C.ink}; cursor: pointer; }
        .bue-crumb { text-decoration: underline; text-underline-offset: 2px; text-decoration-style: dotted; text-decoration-color: ${C.faint}; }
        .bue-crumb:hover { color: ${C.ink} !important; text-decoration-color: ${C.ink}; }
        .bue-crumb.bue-current { text-decoration: none; cursor: default; }
        .bue-btn { transition: background .15s, color .15s; }
        .bue-btn:hover { background: ${C.ink}; color: ${C.bg}; }
        .bue-link { color: ${C.ink}; background: none; border: none; padding: 0; cursor: pointer; font-family: ${mono}; font-size: 11.5px; letter-spacing: .04em; text-decoration: underline; text-underline-offset: 3px; }
        .bue-link:hover { opacity: .6; }
        .bue-choice { display: flex; align-items: center; justify-content: center; gap: 12px; width: 100%; box-sizing: border-box; text-align: center; background: #ffffff; border: 1px solid ${C.rule}; border-radius: 12px; padding: 16px 18px; margin-top: 10px; cursor: pointer; font-family: ${serif}; font-size: 17px; color: ${C.ink}; line-height: 1.4; transition: border-color .15s, background .15s, box-shadow .15s; }
        .bue-choice:hover { border-color: ${C.ink}; box-shadow: 0 1px 0 ${C.ink}; }
        .bue-choice .bue-arrow { color: ${C.mut}; font-family: ${mono}; font-size: 13px; }
        .bue-choice:hover .bue-arrow { color: ${C.ink}; }
        .bue-choice.bue-visited { background: #f2f3f6; border-color: #dcdde6; }
        .bue-choice.bue-visited .bue-qtext { color: ${C.mut}; }
        .bue-choice.bue-visited:hover { border-color: #6a6f86; box-shadow: 0 1px 0 #6a6f86; }
        .bue-visited-tag { display: block; margin-top: 6px; font-family: ${mono}; font-size: 10px; letter-spacing: .12em; text-transform: uppercase; color: #6a6f86; }
        .bue-seg { display: inline-flex; border: 1px solid ${C.rule}; border-radius: 999px; overflow: hidden; }
        .bue-seg button { font-family: ${mono}; font-size: 10.5px; letter-spacing: .08em; text-transform: uppercase; padding: 5px 13px; background: none; border: none; cursor: pointer; color: ${C.mut}; transition: background .15s, color .15s; }
        .bue-seg button:hover { color: ${C.ink}; }
        .bue-seg button.bue-on { background: ${C.ink}; color: ${C.bg}; }
      `}</style>

      {/* language toggle */}
      <div style={{ width: "100%", maxWidth: 560, display: "flex", justifyContent: "center", alignItems: "center", gap: 10, marginBottom: 18 }}>
        <span style={{ ...label, fontSize: 10, color: C.faint }}>language</span>
        <div className="bue-seg">
          {[["research", "Research"], ["simple", "Plain"]].map(([k, lab]) => (
            <button key={k} className={reg === k ? "bue-on" : ""} onClick={() => setReg(k)}>{lab}</button>
          ))}
        </div>
      </div>

      {/* breadcrumb */}
      <div style={{ width: "100%", maxWidth: 560, display: "flex", justifyContent: "center", flexWrap: "wrap", gap: 6, marginBottom: 30 }}>
        {path.map((id, i) => (
          <span key={id} style={{ ...label, fontSize: 10.5 }}>
            {i > 0 && <span style={{ color: C.faint, margin: "0 6px" }}>{"›"}</span>}
            <button className={"bue-crumb" + (i === path.length - 1 ? " bue-current" : "")}
              onClick={() => { if (i !== path.length - 1) enter(id, path.slice(0, i + 1)); }}
              style={{ background: "none", border: "none", padding: 0, cursor: "pointer", color: i === path.length - 1 ? C.ink : C.mut, ...label, fontSize: 10.5 }}>
              {crumb(nodeById[id], reg)}
            </button>
          </span>
        ))}
      </div>

      <div style={col}>
        <div key={viewKey} className="bue-fade" style={{ display: "flex", flexDirection: "column", alignItems: "center", width: "100%" }}>
          {body}
        </div>
      </div>

      <div style={{ ...label, fontSize: 10, color: C.faint, marginTop: 40 }}>{seenCount} of {DATA.findings.length} findings seen</div>
    </div>
  );
}
